/* wms-outbound-obPackingManager-sql-oracle.xml - updateOutboundDetailByPacking - 출고상세 패킹처리 */
UPDATE TWORK_INFO_OB_DT
SET OBDTSTATUSCD = CASE WHEN EXPCTQTY > (PAKQTY + #{topakqty}) THEN '45' /*45:부분패킹*/
						WHEN EXPCTQTY = (PAKQTY + #{topakqty}) THEN '50' /*50:패킹완료*/
						ELSE OBDTSTATUSCD END
	,PAKQTY = PAKQTY + #{topakqty}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}

/* wms-outbound-obPackingManager-sql-oracle.xml - updateOutboundHeaderByPacking - 출고헤더 패킹처리 */
UPDATE TWORK_INFO_OB_HD
SET PCKGSTNBARCODE = COALESCE(#{pakstnbarcode},PCKGSTNBARCODE)
	,PCKGURKEY = #{surkey}
	,PCKGDATE = #{sysdate}
	,PCKGBOXBARCODE = COALESCE(#{pakboxbarcode},PCKGBOXBARCODE)
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
